{!REQUIRESCRIPT("/soap/ajax/52.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/52.0/apex.js")}
const cancelOrder = (order) => {
  order.Cancel_RMA__c = true;
  const res = sforce.connection.update([order], {
    onSuccess: handleSuccess,
    onFailure: handleFailure
  });
  console.log(res);
};
const handleSuccess = () => {
  alert(`Order Cancelled.`);
};
const handleFailure = () => {
  alert(`Order Not Cancelled for this RMA Order, Please Contact Admin`);
};
const handleAlreadyCancelled = (orderSubType) => {
  alert(`${orderSubType} already Cancelled for this RMA Order`);
};
const handleOrderNotFound = (orderSubType) => {
  alert(`${orderSubType} doesn't exist for this RMA Order`);
};
const exec = (id, orderSubType) => {
  console.log(id);
  const order =  sforce.connection.query(
    `SELECT Id, Cancel_RMA__c
    FROM Order
    WHERE
        RMA_Request__c = '${id}'
        AND Order_Sub_Type__c = '${orderSubType}'
        AND Type = 'RMA' LIMIT 1`
  ).records;
  if (!order) {
    handleOrderNotFound(orderSubType)
  } else if (order.Cancel_RMA__c === "true") {
    handleAlreadyCancelled(orderSubType);
  } else {
    cancelOrder(order);
  }

  console.log(order);
  debugger;
};
const c = window.confirm("Do you want to cancel the Part order request?");
console.log("C: ", c);
if (c) {
  exec("{!RMA_Order__c.Id}", "Part Order");
}
